\frac{3}{x} + \frac{3}{z} + \frac{1}{xz} &\le \left(\frac{16}{(x + z)^2} + \frac{1}{xz}\right) \\
&\le \left(\frac{1}{x + z - \frac{1}{2}} + \frac{16}{x + z - \frac{1}{2}}\right) \\
&= \frac{17}{x + z - \frac{1}{2}}. 
